// services/auth/dotypos-auth.service.ts
import { jwtDecode } from 'jwt-decode';

interface TokenResponse {
  access_token: string;
  refresh_token: string;
  expires_in: number;
  token_type: string;
}

interface DecodedToken {
  exp: number;
  sub: string;
  // Other JWT claims
}

export class DotyposAuthService {
  private static instance: DotyposAuthService;
  private accessToken: string | null = null;
  private refreshToken: string | null = null;
  private expiresAt: number = 0;

  // Singleton pattern
  public static getInstance(): DotyposAuthService {
    if (!DotyposAuthService.instance) {
      DotyposAuthService.instance = new DotyposAuthService();
    }
    return DotyposAuthService.instance;
  }

  // Initialize with tokens if they exist in storage
  constructor() {
    this.loadTokensFromStorage();
  }

  private loadTokensFromStorage(): void {
    if (typeof window !== 'undefined') {
      try {
        const tokens = localStorage.getItem('dotypos_tokens');
        if (tokens) {
          const parsedTokens = JSON.parse(tokens);
          this.accessToken = parsedTokens.accessToken;
          this.refreshToken = parsedTokens.refreshToken;
          this.expiresAt = parsedTokens.expiresAt;
        }
      } catch (error) {
        console.error('Failed to load tokens from storage:', error);
        this.clearTokens();
      }
    }
  }

  private saveTokensToStorage(): void {
    if (typeof window !== 'undefined') {
      try {
        localStorage.setItem('dotypos_tokens', JSON.stringify({
          accessToken: this.accessToken,
          refreshToken: this.refreshToken,
          expiresAt: this.expiresAt,
        }));
      } catch (error) {
        console.error('Failed to save tokens to storage:', error);
      }
    }
  }

  public clearTokens(): void {
    this.accessToken = null;
    this.refreshToken = null;
    this.expiresAt = 0;
    if (typeof window !== 'undefined') {
      localStorage.removeItem('dotypos_tokens');
    }
  }

  public isAuthenticated(): boolean {
    return !!this.accessToken && this.expiresAt > Date.now();
  }

  public async login(code: string): Promise<boolean> {
    try {
      const response = await fetch('/api/auth/dotypos/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ code }),
      });

      if (!response.ok) {
        throw new Error(`Authentication failed: ${response.statusText}`);
      }

      const data: TokenResponse = await response.json();
      return this.handleTokenResponse(data);
    } catch (error) {
      console.error('Login error:', error);
      this.clearTokens();
      return false;
    }
  }

  private handleTokenResponse(data: TokenResponse): boolean {
    try {
      const decodedToken = jwtDecode<DecodedToken>(data.access_token);

      this.accessToken = data.access_token;
      this.refreshToken = data.refresh_token;
      // Convert expiration to milliseconds and subtract a buffer (30s)
      this.expiresAt = (decodedToken.exp * 1000) - 30000;

      this.saveTokensToStorage();
      return true;
    } catch (error) {
      console.error('Token handling error:', error);
      this.clearTokens();
      return false;
    }
  }

  public async getAccessToken(): Promise<string | null> {
    // If token is expired or about to expire, refresh it
    if (this.accessToken && this.expiresAt <= Date.now() + 60000) {
      await this.refreshAccessToken();
    }

    return this.accessToken;
  }

  private async refreshAccessToken(): Promise<boolean> {
    if (!this.refreshToken) {
      return false;
    }

    try {
      const response = await fetch('/api/auth/dotypos/refresh', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ refresh_token: this.refreshToken }),
      });

      if (!response.ok) {
        throw new Error(`Token refresh failed: ${response.statusText}`);
      }

      const data: TokenResponse = await response.json();
      return this.handleTokenResponse(data);
    } catch (error) {
      console.error('Token refresh error:', error);
      this.clearTokens();
      return false;
    }
  }

  public async logout(): Promise<void> {
    if (this.accessToken) {
      try {
        await fetch('/api/auth/dotypos/logout', {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${this.accessToken}`,
          },
        });
      } catch (error) {
        console.error('Logout error:', error);
      }
    }

    this.clearTokens();
  }
}

export const dotyposAuth = DotyposAuthService.getInstance();
```

