export function DotyposAuthProvider({ children }: { children: ReactNode }) {
  const auth = useDotyposAuth();

  return (
    <DotyposAuthContext.Provider value={auth}>
      {children}
    </DotyposAuthContext.Provider>
  );
}

export function useDotyposAuthContext() {
  const context = useContext(DotyposAuthContext);
  if (context === undefined) {
    throw new Error('useDotyposAuthContext must be used within a DotyposAuthProvider');
  }
  return context;
}
