6. **Create OAuth2 Callback Page**:
```typescript
// app/[locale]/auth/dotypos/callback/page.tsx
'use client';

import { useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useDotyposAuthContext } from '@/contexts/dotypos-auth-context';
import { createTranslator } from '@/paraglide/runtime';

export default function DotyposCallback({ params }: { params: { locale: string } }) {
  const t = createTranslator(params.locale);
  const router = useRouter();
  const searchParams = useSearchParams();
  const { login } = useDotyposAuthContext();

  const [status, setStatus] = useState<'loading' | 'success' | 'error'>('loading');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function handleCallback() {
      try {
        const code = searchParams.get('code');
        const error = searchParams.get('error');

        if (error) {
          setStatus('error');
          setError(error);
          return;
        }

        if (!code) {
          setStatus('error');
          setError('No authorization code provided');
          return;
        }

        const success = await login(code);

        if (success) {
          setStatus('success');
          // Redirect to dashboard or another protected page
          setTimeout(() => {
            router.push('/dashboard');
          }, 1500);
        } else {
          setStatus('error');
          setError('Authentication failed');
        }
      } catch (error) {
        setStatus('error');
        setError(error instanceof Error ? error.message : 'Unknown error');
      }
    }

    handleCallback();
  }, [searchParams, login, router]);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4">
      <div className="w-full max-w-md p-6 bg-white rounded-lg shadow-md">
        <h1 className="text-2xl font-bold mb-4">
          {status === 'loading' && t('auth.processing')}
          {status === 'success' && t('auth.success')}
          {status === 'error' && t('auth.failed')}
        </h1>

        {status === 'loading' && (
          <div className="flex justify-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
          </div>
        )}

        {status === 'success' && (
          <p className="text-green-600">{t('auth.redirecting')}</p>
        )}

        {status === 'error' && error && (
          <p className="text-red-600">{error}</p>
        )}
      </div>
    </div>
  );
}
```

