## Objective
Implement a comprehensive table management service for Dotypos integration that handles table data, availability, and selection logic.

## Implementation Steps

1. **Create Table Management Service Module**:
```typescript
// services/dotypos/table-management.service.ts
import { DotyposAuthService } from '../auth/dotypos-auth.service';

export interface Table {
  id: string;
  name: string;
  branchId: string;
  capacity: number;
  isAvailable: boolean;
  position?: {
    x: number;
    y: number;
    floor: number;
  };
  // Additional properties as needed
}

export interface TableAvailabilityParams {
  branchId: string;
  date: string; // ISO format
  timeSlot: string;
  partySize: number;
}

export class TableManagementService {
  private static instance: TableManagementService;
  private authService: DotyposAuthService;
  private baseUrl: string;

  private constructor() {
    this.authService = DotyposAuthService.getInstance();
    this.baseUrl = process.env.NEXT_PUBLIC_DOTYPOS_API_URL || '';
  }

  public static getInstance(): TableManagementService {
    if (!TableManagementService.instance) {
      TableManagementService.instance = new TableManagementService();
    }
    return TableManagementService.instance;
  }

  /**
   * Fetch all tables for a specific branch
   */
  public async getAllTables(branchId: string): Promise<Table[]> {
    try {
      const token = await this.authService.getAccessToken();
      const response = await fetch(`${this.baseUrl}/branches/${branchId}/tables`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch tables: ${response.status}`);
      }

      const data = await response.json();
      return this.mapApiResponseToTables(data);
    } catch (error) {
      console.error('Error fetching tables:', error);
      throw error;
    }
  }

  /**
   * Check availability of tables based on date, time, and party size
   */
  public async checkTableAvailability(params: TableAvailabilityParams): Promise<Table[]> {
    try {
      const token = await this.authService.getAccessToken();
      const response = await fetch(`${this.baseUrl}/branches/${params.branchId}/tables/availability`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          date: params.date,
          timeSlot: params.timeSlot,
          partySize: params.partySize
        })
      });

      if (!response.ok) {
        throw new Error(`Failed to check table availability: ${response.status}`);
      }

      const data = await response.json();
      return this.mapApiResponseToTables(data);
    } catch (error) {
      console.error('Error checking table availability:', error);
      throw error;
    }
  }

  /**
   * Find suitable tables based on party size and availability
   */
  public async findSuitableTables(params: TableAvailabilityParams): Promise<Table[]> {
    const availableTables = await this.checkTableAvailability(params);

    // Filter tables that can accommodate the party size
    return availableTables.filter(table => 
      table.capacity >= params.partySize && 
      table.isAvailable
    );
  }

  /**
   * Get tables with floor plan positioning data
   */
  public async getTablesWithPositionData(branchId: string): Promise<Table[]> {
    const tables = await this.getAllTables(branchId);
    return tables.filter(table => table.position !== undefined);
  }

  /**
   * Map API response to Table objects
   */
  private mapApiResponseToTables(data: any[]): Table[] {
    return data.map(item => ({
      id: item.id,
      name: item.name,
      branchId: item.branchId,
      capacity: item.capacity,
      isAvailable: item.isAvailable || false,
      position: item.position ? {
        x: item.position.x,
        y: item.position.y,
        floor: item.position.floor || 1
      } : undefined
    }));
  }
}

// Export a singleton instance
export const tableManagementService = TableManagementService.getInstance();
```

