  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchTables = async () => {
      setLoading(true);
      setError(null);
      try {
        const suitableTables = await tableManagementService.findSuitableTables(params);
        setTables(suitableTables);

        // Auto-select the first suitable table if available
        if (suitableTables.length > 0 && !selectedTable) {
          setSelectedTable(suitableTables[0]);
        }
      } catch (err) {
        setError('Failed to fetch available tables. Please try again.');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    if (params.branchId && params.date && params.timeSlot && params.partySize) {
      fetchTables();
    }
  }, [params.branchId, params.date, params.timeSlot, params.partySize]);

  const selectTable = (tableId: string) => {
    const table = tables.find(t => t.id === tableId);
    if (table) {
      setSelectedTable(table);
      return true;
    }
    return false;
  };

  return {
    tables,
    selectedTable,
    selectTable,
    loading,
    error
  };
}
```

