    ];
  }

  public static getInstance(): LoyaltyService {
    if (!LoyaltyService.instance) {
      LoyaltyService.instance = new LoyaltyService();
    }
    return LoyaltyService.instance;
  }

  /**
   * Get available rewards for a customer based on their points
   */
  async getAvailableRewards(customerId: string): Promise<LoyaltyRule[]> {
    const customer = await this.customerService.getCustomerById(customerId);
    if (!customer) {
      throw new Error(`Customer with ID ${customerId} not found`);
    }

    return this.loyaltyRules.filter(rule => 
      (customer.loyaltyPoints || 0) >= rule.pointsRequired
    );
  }

  /**
   * Add points to customer account
   */
  async addPoints(customerId: string, points: number, reason?: string): Promise<Customer> {
    return this.customerService.addLoyaltyPoints(customerId, points);
  }

  /**
   * Redeem points for a reward
   */
  async redeemReward(customerId: string, rewardId: string): Promise<boolean> {
    const customer = await this.customerService.getCustomerById(customerId);
    if (!customer) {
      throw new Error(`Customer with ID ${customerId} not found`);
    }

    const reward = this.loyaltyRules.find(r => r.id === rewardId);
    if (!reward) {
      throw new Error(`Reward with ID ${rewardId} not found`);
    }

    if ((customer.loyaltyPoints || 0) < reward.pointsRequired) {
      throw new Error(`Customer does not have enough points for this reward`);
    }

    // Deduct points
    await this.customerService.updateCustomer(customerId, {
      loyaltyPoints: (customer.loyaltyPoints || 0) - reward.pointsRequired
    });

    // Record redemption (could be expanded to store in a separate table)
    // ...

    return true;
  }
}
