      isSystem: false
    };

    this.tagDefinitions.push(newTag);
    return newTag;
  }

  /**
   * Tag a customer
   */
  async tagCustomer(customerId: string, tagIds: string[]): Promise<Customer> {
    // Validate that all tags exist
    const validTagIds = this.tagDefinitions.map(t => t.id);
    const invalidTags = tagIds.filter(id => !validTagIds.includes(id));

    if (invalidTags.length > 0) {
      throw new Error(`Invalid tag IDs: ${invalidTags.join(', ')}`);
    }

    return this.customerService.addCustomerTags(customerId, tagIds);
  }

  /**
   * Remove tags from a customer
   */
  async removeCustomerTags(customerId: string, tagIds: string[]): Promise<Customer> {
    return this.customerService.removeCustomerTags(customerId, tagIds);
  }

  /**
   * Find customers by tags
   */
  async findCustomersByTags(tagIds: string[]): Promise<Customer[]> {
    return this.customerService.getAllCustomers({ tags: tagIds });
  }
}
```

7. **Implement API Error Handling**:
```typescript
// utils/api-error-handling.ts
export class ApiError extends Error {
  statusCode: number;

  constructor(message: string, statusCode: number) {
    super(message);
    this.statusCode = statusCode;
    this.name = 'ApiError';
  }
}

export function handleApiError(error: unknown): never {
  if (error instanceof ApiError) {
    throw error;
  }

  if (error instanceof Error) {
    throw new ApiError(error.message, 500);
  }

  throw new ApiError('Unknown error occurred', 500);
}
```

8. **Create Customer Data Export/Import Functionality**:
```typescript
// services/dotypos/customer-import-export.service.ts
import { DotyposCustomerService, Customer } from './customer-management.service';
import { validateEmail, validatePhone, normalizeEmail, normalizePhone } from '@/utils/customer-validation';

export class CustomerImportExportService {
  private static instance: CustomerImportExportService;
  private customerService: DotyposCustomerService;

  private constructor() {
    this.customerService = DotyposCustomerService.getInstance();
  }

  public static getInstance(): CustomerImportExportService {
    if (!CustomerImportExportService.instance) {
      CustomerImportExportService.instance = new CustomerImportExportService();
    }
    return CustomerImportExportService.instance;
  }

  /**
   * Export customers to CSV format
   */
  async exportCustomersToCsv(): Promise<string> {
    const customers = await this.customerService.getAllCustomers();

    // Create CSV header
    const headers = ['id', 'firstName', 'lastName', 'email', 'phone', 'isGuest', 'loyaltyPoints', 'tags', 'createdAt', 'updatedAt'];

    // Create CSV rows
    const rows = customers.map(customer => [
      customer.id,
      customer.firstName,
      customer.lastName,
      customer.email || '',
      customer.phone || '',
      customer.isGuest ? 'Yes' : 'No',
      customer.loyaltyPoints || 0,
      (customer.tags || []).join(';'),
      customer.createdAt,
      customer.updatedAt
    ]);

    // Combine header and rows
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    return csvContent;
  }

  /**
   * Import customers from CSV format
   */
  async importCustomersFromCsv(csvContent: string): Promise<{ 
    imported: number, 
    skipped: number, 
    errors: Array<{ line: number, error: string }> 
  }> {
    const lines = csvContent.split('\n');
    const headers = lines[0].split(',');

    const result = {
      imported: 0,
      skipped: 0,
      errors: [] as Array<{ line: number, error: string }>
    };

    // Process each line (skip header)
    for (let i = 1; i < lines.length; i++) {
      try {
        const line = lines[i].trim();
        if (!line) continue;

        const values = line.split(',');
        const customerData: any = {};

        // Map CSV values to customer properties
        headers.forEach((header, index) => {
          if (header === 'tags') {
            customerData[header] = values[index] ? values[index].split(';') : [];
          } else if (header === 'isGuest') {
            customerData[header] = values[index].toLowerCase() === 'yes';
          } else if (header === 'loyaltyPoints') {
            customerData[header] = parseInt(values[index], 10) || 0;
          } else {
            customerData[header] = values[index];
          }
        });

        // Validate and normalize email/phone
        if (customerData.email) {
          if (!validateEmail(customerData.email)) {
            throw new Error(`Invalid email: ${customerData.email}`);
          }
          customerData.email = normalizeEmail(customerData.email);
        }

        if (customerData.phone) {
          if (!validatePhone(customerData.phone)) {
            throw new Error(`Invalid phone: ${customerData.phone}`);
          }
          customerData.phone = normalizePhone(customerData.phone);
        }

        // Check for duplicates
        const duplicates = await this.customerService.findPotentialDuplicates({
          email: customerData.email,
          phone: customerData.phone
        });

        if (duplicates.length > 0) {
          result.skipped++;
          continue;
        }

        // Create the customer
        await this.customerService.createCustomer(customerData);
        result.imported++;
      } catch (error) {
        result.errors.push({
          line: i,
          error: error instanceof Error ? error.message : String(error)
        });
      }
    }

    return result;
  }
}
```

