## Objective
Implement a comprehensive branch management system for Dotypos integration that enables multi-location support throughout the application.

## Implementation Steps

1. **Create Branch Management Service Module**:
```typescript
// services/dotypos/branch-management.service.ts
import { DotyposAuthService } from '../auth/dotypos-auth.service';

export interface Branch {
  id: string;
  name: string;
  address: {
    street: string;
    city: string;
    postalCode: string;
    country: string;
  };
  contactInfo: {
    phone?: string;
    email?: string;
  };
  openingHours?: Record<string, { open: string; close: string }>;
  isActive: boolean;
}

export class BranchManagementService {
  private static instance: BranchManagementService;
  private authService: DotyposAuthService;
  private branches: Branch[] = [];
  private selectedBranchId: string | null = null;

  private constructor() {
    this.authService = DotyposAuthService.getInstance();
  }

  public static getInstance(): BranchManagementService {
    if (!BranchManagementService.instance) {
      BranchManagementService.instance = new BranchManagementService();
    }
    return BranchManagementService.instance;
  }

  /**
   * Fetches all available branches from the Dotypos API
   */
  public async getAllBranches(forceRefresh = false): Promise<Branch[]> {
    if (this.branches.length > 0 && !forceRefresh) {
      return this.branches;
    }

    try {
      const token = await this.authService.getAccessToken();
      const response = await fetch(`${process.env.NEXT_PUBLIC_DOTYPOS_API_URL}/branches`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch branches: ${response.statusText}`);
      }

      const data = await response.json();
      this.branches = data.branches.map((branch: any) => ({
        id: branch.id,
        name: branch.name,
        address: branch.address,
        contactInfo: branch.contactInfo,
        openingHours: branch.openingHours,
        isActive: branch.isActive,
      }));

      // If no branch is selected and we have branches, select the first active one
      if (!this.selectedBranchId && this.branches.length > 0) {
        const activeBranch = this.branches.find(branch => branch.isActive);
        if (activeBranch) {
          this.selectedBranchId = activeBranch.id;
        }
      }

      return this.branches;
    } catch (error) {
      console.error('Error fetching branches:', error);
      throw error;
    }
  }

  /**
   * Gets the currently selected branch
   */
  public async getSelectedBranch(): Promise<Branch | null> {
    if (!this.selectedBranchId) {
      return null;
    }

    // Ensure branches are loaded
    if (this.branches.length === 0) {
      await this.getAllBranches();
    }

    return this.branches.find(branch => branch.id === this.selectedBranchId) || null;
  }

  /**
   * Sets the selected branch by ID
   */
  public async selectBranch(branchId: string): Promise<Branch | null> {
    // Ensure branches are loaded
    if (this.branches.length === 0) {
      await this.getAllBranches();
    }

    const branch = this.branches.find(branch => branch.id === branchId);
    if (!branch) {
      throw new Error(`Branch with ID ${branchId} not found`);
    }

    this.selectedBranchId = branchId;
    return branch;
  }

  /**
   * Gets branch by ID
   */
  public async getBranchById(branchId: string): Promise<Branch | null> {
    // Ensure branches are loaded
    if (this.branches.length === 0) {
      await this.getAllBranches();
    }

    return this.branches.find(branch => branch.id === branchId) || null;
  }

  /**
   * Validates if a table belongs to the currently selected branch
   */
  public async validateTableBranchRelationship(tableId: string): Promise<boolean> {
    const tableService = (await import('./table-management.service')).default.getInstance();
    const table = await tableService.getTableById(tableId);

    if (!table) {
      return false;
    }

    const selectedBranch = await this.getSelectedBranch();
    if (!selectedBranch) {
      return false;
    }

    return table.branchId === selectedBranch.id;
  }
}

export default BranchManagementService;
```

2. **Create Branch Context Provider**:
```tsx
// contexts/branch-context.tsx
import React, { createContext, useContext, useState, useEffect } from 'react';
import { Branch, BranchManagementService } from '@/services/dotypos/branch-management.service';

interface BranchContextType {
  branches: Branch[];
  selectedBranch: Branch | null;
  isLoading: boolean;
  error: Error | null;
  selectBranch: (branchId: string) => Promise<void>;
  refreshBranches: () => Promise<void>;
}

const BranchContext = createContext<BranchContextType | undefined>(undefined);

export const BranchProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [branches, setBranches] = useState<Branch[]>([]);
  const [selectedBranch, setSelectedBranch] = useState<Branch | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<Error | null>(null);

  const branchService = BranchManagementService.getInstance();

  const loadBranches = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const fetchedBranches = await branchService.getAllBranches();
      setBranches(fetchedBranches);

      const selected = await branchService.getSelectedBranch();
      setSelectedBranch(selected);
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Failed to load branches'));
    } finally {
      setIsLoading(false);
    }
  };

  const refreshBranches = async () => {
    setIsLoading(true);
    try {
      const fetchedBranches = await branchService.getAllBranches(true);
      setBranches(fetchedBranches);

      const selected = await branchService.getSelectedBranch();
      setSelectedBranch(selected);
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Failed to refresh branches'));
    } finally {
      setIsLoading(false);
    }
  };

  const selectBranch = async (branchId: string) => {
    setIsLoading(true);
    try {
      const branch = await branchService.selectBranch(branchId);
      setSelectedBranch(branch);
    } catch (err) {
      setError(err instanceof Error ? err : new Error(`Failed to select branch ${branchId}`));
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadBranches();
  }, []);

  return (
    <BranchContext.Provider
      value={{
        branches,
        selectedBranch,
        isLoading,
        error,
        selectBranch,
        refreshBranches,
      }}
    >
      {children}
    </BranchContext.Provider>
  );
};

export const useBranch = () => {
  const context = useContext(BranchContext);
  if (context === undefined) {
    throw new Error('useBranch must be used within a BranchProvider');
  }
  return context;
};
```

