## Objective
Implement a comprehensive webhook system for Dotypos integration that enables real-time updates to the application when changes occur in the Dotypos system.

## Implementation Steps

1. **Create Webhook Registration Service**:
```typescript
// services/dotypos/webhook-registration.service.ts
import { DotyposAuthService } from '../auth/dotypos-auth.service';

export class DotyposWebhookService {
  private static instance: DotyposWebhookService;
  private authService: DotyposAuthService;
  private baseUrl: string;

  private constructor() {
    this.authService = DotyposAuthService.getInstance();
    this.baseUrl = process.env.NEXT_PUBLIC_DOTYPOS_API_URL || '';
  }

  public static getInstance(): DotyposWebhookService {
    if (!DotyposWebhookService.instance) {
      DotyposWebhookService.instance = new DotyposWebhookService();
    }
    return DotyposWebhookService.instance;
  }

  /**
   * Register a new webhook with Dotypos
   */
  async registerWebhook(callbackUrl: string, events: string[]): Promise<string> {
    const token = await this.authService.getAccessToken();

    const response = await fetch(`${this.baseUrl}/api/v1/webhooks`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        url: callbackUrl,
        events: events,
        active: true
      })
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Failed to register webhook: ${error.message}`);
    }

    const data = await response.json();
    return data.id;
  }

  /**
   * Delete a webhook from Dotypos
   */
  async deleteWebhook(webhookId: string): Promise<void> {
    const token = await this.authService.getAccessToken();

    const response = await fetch(`${this.baseUrl}/api/v1/webhooks/${webhookId}`, {
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Failed to delete webhook: ${error.message}`);
    }
  }

  /**
   * List all registered webhooks
   */
  async listWebhooks(): Promise<any[]> {
    const token = await this.authService.getAccessToken();

    const response = await fetch(`${this.baseUrl}/api/v1/webhooks`, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });

    if (!response.ok) {
      const error = await response.json();
      throw new Error(`Failed to list webhooks: ${error.message}`);
    }

    const data = await response.json();
    return data;
  }
}
