```typescript
// app/api/webhooks/dotypos/route.ts
import { NextRequest, NextResponse } from 'next/server';
import crypto from 'crypto';
import { WebSocketServer } from '@/services/websocket/websocket-server';

// Webhook secret from environment variables
const WEBHOOK_SECRET = process.env.DOTYPOS_WEBHOOK_SECRET || '';

export async function POST(request: NextRequest) {
  // Set a 21-second timeout to respond before Dotypos times out
  const timeoutPromise = new Promise((_, reject) => {
    setTimeout(() => reject(new Error('Webhook processing timeout')), 20000);
  });

  try {
    // Process the webhook with a timeout
    const result = await Promise.race([
      processWebhook(request),
      timeoutPromise
    ]);

    return NextResponse.json({ success: true, message: 'Webhook processed successfully' }, { status: 200 });
  } catch (error) {
    console.error('Webhook processing error:', error);
    return NextResponse.json({ success: false, message: 'Webhook processing failed' }, { status: 500 });
  }
}

async function processWebhook(request: NextRequest) {
  // Get the signature from headers
  const signature = request.headers.get('x-dotypos-signature') || '';

  // Get the raw body
  const rawBody = await request.text();

  // Validate the webhook signature
  if (!validateSignature(rawBody, signature)) {
    throw new Error('Invalid webhook signature');
  }

  // Parse the webhook payload
  const payload = JSON.parse(rawBody);

  // Process different event types
  switch (payload.event) {
    case 'reservation.created':
    case 'reservation.updated':
    case 'reservation.deleted':
      await handleReservationEvent(payload);
      break;
    case 'table.updated':
      await handleTableEvent(payload);
      break;
    // Add more event handlers as needed
    default:
      console.log(`Unhandled webhook event type: ${payload.event}`);
  }
}

function validateSignature(payload: string, signature: string): boolean {
  if (!WEBHOOK_SECRET || !signature) {
    return false;
  }

  const hmac = crypto.createHmac('sha256', WEBHOOK_SECRET);
  const calculatedSignature = hmac.update(payload).digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(calculatedSignature),
    Buffer.from(signature)
  );
}

async function handleReservationEvent(payload: any) {
  // Process reservation events
  const { data, event } = payload;

  // Notify connected clients about the reservation update
  WebSocketServer.getInstance().broadcastMessage('reservations', {
    type: event,
    data: data
  });

  // Additional processing logic here
  // e.g., update database, trigger notifications, etc.
}

async function handleTableEvent(payload: any) {
  // Process table events
  const { data, event } = payload;

  // Notify connected clients about the table update
  WebSocketServer.getInstance().broadcastMessage('tables', {
    type: event,
    data: data
  });

  // Additional processing logic here
}
