4. **Create WebSocket Client for Frontend**:
```typescript
// hooks/use-real-time-updates.ts
import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';

interface UseRealTimeUpdatesOptions {
  channel: string;
  onMessage?: (data: any) => void;
}

export function useRealTimeUpdates({ channel, onMessage }: UseRealTimeUpdatesOptions) {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [lastMessage, setLastMessage] = useState<any>(null);

  useEffect(() => {
    // Create socket connection
    const socketInstance = io(process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000', {
      path: '/api/socket'
    });

    // Set up event handlers
    socketInstance.on('connect', () => {
      console.log('Connected to WebSocket server');
      setIsConnected(true);

      // Subscribe to the specified channel
      socketInstance.emit('subscribe', channel);
    });

    socketInstance.on('disconnect', () => {
      console.log('Disconnected from WebSocket server');
      setIsConnected(false);
    });

    socketInstance.on('message', (data) => {
      console.log(`Received message on channel ${channel}:`, data);
      setLastMessage(data);

      if (onMessage) {
        onMessage(data);
      }
    });

    setSocket(socketInstance);

    // Cleanup on unmount
    return () => {
      if (socketInstance) {
        socketInstance.emit('unsubscribe', channel);
        socketInstance.disconnect();
      }
    };
  }, [channel, onMessage]);

  return { isConnected, lastMessage, socket };
}
