import { DotyposWebhookService } from './webhook-registration.service';

export async function initializeWebhooks() {
  const webhookService = DotyposWebhookService.getInstance();
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000';
  const webhookEndpoint = `${siteUrl}/api/webhooks/dotypos`;

  try {
