    const webhookExists = existingWebhooks.some(
      (webhook: any) => webhook.url === webhookEndpoint && webhook.active
    );

    if (!webhookExists) {
      // Register webhook with all required events
      await webhookService.registerWebhook(webhookEndpoint, [
        'reservation.created',
        'reservation.updated',
        'reservation.deleted',
        'table.updated',
        'customer.created',
        'customer.updated'
      ]);
      console.log('Dotypos webhook registered successfully');
    } else {
      console.log('Dotypos webhook already exists');
    }
  } catch (error) {
    console.error('Failed to initialize Dotypos webhook:', error);
  }
}
