export function ReservationLiveUpdates() {
  const [reservations, setReservations] = useState<any[]>([]);

  // Subscribe to real-time updates for reservations
  const { isConnected, lastMessage } = useRealTimeUpdates({
    channel: 'reservations',
    onMessage: (data) => {
      // Handle different event types
      if (data.type === 'reservation.created') {
        setReservations(prev => [...prev, data.data]);
      } else if (data.type === 'reservation.updated') {
        setReservations(prev => 
          prev.map(res => res.id === data.data.id ? data.data : res)
        );
      } else if (data.type === 'reservation.deleted') {
        setReservations(prev => 
          prev.filter(res => res.id !== data.data.id)
        );
      }
    }
  });

  // Initial load of reservations
  useEffect(() => {
    // Load initial reservations from API
    async function loadReservations() {
      try {
        const response = await fetch('/api/reservations');
        if (response.ok) {
          const data = await response.json();
          setReservations(data);
        }
      } catch (error) {
        console.error('Failed to load reservations:', error);
      }
    }

    loadReservations();
  }, []);

  return (
