// tests/utils/test-helpers.ts
import { vi } from 'vitest';

export function mockFetch(status: number, responseData: any) {
  return vi.fn().mockResolvedValueOnce({
    ok: status >= 200 && status < 300,
    status,
    json: async () => responseData
  });
}

export function mockLocalStorage() {
  let store: Record<string, string> = {};

  return {
    getItem: vi.fn((key: string) => store[key] || null),
    setItem: vi.fn((key: string, value: string) => {
      store[key] = value;
    }),
    removeItem: vi.fn((key: string) => {
      delete store[key];
    }),
    clear: vi.fn(() => {
      store = {};
    })
  };
}

export function setupAuthenticatedTest() {
  // Helper to set up authenticated test environment
  const localStorage = mockLocalStorage();
  vi.stubGlobal('localStorage', localStorage);

  localStorage.setItem('dotypos_access_token', 'test-access-token');
  localStorage.setItem('dotypos_refresh_token', 'test-refresh-token');

  return { localStorage };
}
